import { toDate } from '../toDate/index.js';

/**
 * @name isWeekday
 * @category Weekday Helpers
 * @summary Is the given date a weekday (Mon-Fri)?
 *
 * @param date - The date to check
 * @returns True if the date is Monday through Friday
 *
 * @example
 * isWeekday(new Date(2024, 0, 15)) // Monday
 * //=> true
 * isWeekday(new Date(2024, 0, 14)) // Sunday
 * //=> false
 */
export function isWeekday(date: Date | number | string): boolean {
  const day = toDate(date).getDay();
  return day >= 1 && day <= 5;
}

import { describe, it, expect } from 'vitest';
import { isWeekday } from './index.js';

describe('isWeekday', () => {
  it('returns true for Monday', () => {
    // Jan 15, 2024 is Monday
    expect(isWeekday(new Date(2024, 0, 15))).toBe(true);
  });

  it('returns true for Friday', () => {
    // Jan 19, 2024 is Friday
    expect(isWeekday(new Date(2024, 0, 19))).toBe(true);
  });

  it('returns false for Saturday', () => {
    // Jan 20, 2024 is Saturday
    expect(isWeekday(new Date(2024, 0, 20))).toBe(false);
  });

  it('returns false for Sunday', () => {
    // Jan 21, 2024 is Sunday
    expect(isWeekday(new Date(2024, 0, 21))).toBe(false);
  });
});
